"use server";

import { createClient } from "@supabase/supabase-js";
import type { Database } from "@/lib/supabase";
import { createAppointment, getGarageById, createAdminGarage } from "@/lib/supabase-service";
import { sendNotificationEmail } from "@/lib/email-service";
import { format } from "date-fns";
import { fr } from "date-fns/locale";

// Helper to get Admin Supabase client to bypass RLS for lookups/inserts during public flows
function getServiceSupabase() {
    const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
    const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;
    return createClient<Database>(supabaseUrl, supabaseKey);
}

export async function submitBooking(appointment: Database['public']['Tables']['appointments']['Insert']) {
    // 1. Insert into database
    // We can use the service layer since this is a public endpoint now secured by server execution
    const newAppt = await createAppointment(appointment);

    // 2. Lookup Garage Information
    const garage = await getGarageById(appointment.garage_id);

    const serviceClient = getServiceSupabase();
    const { data: adminGarage } = await serviceClient
        .from('admin_garages')
        .select('email')
        .eq('garage_id', appointment.garage_id)
        .maybeSingle();

    const formattedDate = format(new Date(appointment.date), "dd/MM/yyyy '├á' HH:mm", { locale: fr });
    const vehicleName = appointment.plate || appointment.vehicle;

    // 3. Send Partner Email
    if (adminGarage?.email) {
        try {
            await sendNotificationEmail('partner_alert_new_appointment', {
                partnerEmail: adminGarage.email,
                vehicle: vehicleName,
                date: formattedDate
            });
        } catch (e) {
            console.error("Failed to send partner alert:", e);
        }
    }

    // 4. Send Client Email
    if (appointment.email) {
        try {
            await sendNotificationEmail('client_booking_confirmation', {
                clientEmail: appointment.email,
                clientName: appointment.client_name,
                vehicle: vehicleName,
                date: formattedDate,
                garageName: garage.name,
                garageAddress: garage.address
            });
        } catch (e) {
            console.error("Failed to send client confirmation:", e);
        }
    }

    return newAppt;
}

export async function submitPartnerRegistration(partnerData: Database['public']['Tables']['admin_garages']['Insert']) {
    // 1. Insert admin garage securely from server
    const serviceClient = getServiceSupabase();

    // We use service client to ensure insert succeeds regardless of restrictive RLS
    // Registration logic is thus entirely controlled by the server
    const { data, error } = await (serviceClient.from('admin_garages') as any)
        .insert(partnerData)
        .select()
        .single();

    if (error) throw new Error("Erreur DB: " + error.message);

    // 2. Send Admin Alert Email
    try {
        await sendNotificationEmail('admin_alert_new_partner', {
            name: partnerData.name,
            city: partnerData.city,
            email: partnerData.email,
            phone: partnerData.phone
        });
    } catch (e) {
        console.error("Failed to send admin alert email:", e);
    }

    return data;
}

"use server";

import { cookies } from "next/headers";
import { createClient } from "@supabase/supabase-js";
import type { Database } from "@/lib/supabase";
import * as crypto from "crypto";
import { sendNotificationEmail } from "@/lib/email-service";
import { 
    getAdminGarages, 
    getAppointments, 
    updateAdminGarageStatus, 
    deleteAdminGarage 
} from "@/lib/supabase-service";

// Internal helper to verify Admin session
async function verifyAdminAuth() {
    const cookieStore = await cookies();
    const token = cookieStore.get('sb-access-token')?.value;
    if (!token) throw new Error("Non authentifi├⌐ en tant qu'administrateur");

    const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
    const supabaseAnonKey = process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;

    // Client used purely to decode and verify token server-side via Supabase GoTrue Auth
    const supabase = createClient<Database>(supabaseUrl, supabaseAnonKey, {
        global: { headers: { Authorization: `Bearer ${token}` } }
    });

    const { data: { user }, error: authError } = await supabase.auth.getUser(token);
    if (authError || !user) throw new Error("Session invalide ou expir├⌐e");

    // Check against admin_users
    const { data: adminUser, error: adminError } = await supabase
        .from('admin_users')
        .select('*')
        .eq('email', user.email)
        .single();

    if (adminError || !adminUser) throw new Error("Acc├¿s refus├⌐ : R├┤le administrateur requis");

    return user;
}

// Ensure mutations bypass RLS confidently only verified via the Server Action wrapper
// since `supabase-service.ts` uses the Anon Key internally which is risky on client-side
export async function secureGetAdminData() {
    await verifyAdminAuth();
    // Proxy call
    const [garages, appointments] = await Promise.all([
        getAdminGarages(),
        getAppointments()
    ]);
    return { garages, appointments };
}

export async function secureDeleteAdminGarage(adminGarageId: number) {
    await verifyAdminAuth();
    return deleteAdminGarage(adminGarageId);
}

export async function secureUpdateAdminGarageStatus(adminGarageId: number, status: string) {
    await verifyAdminAuth();
    return updateAdminGarageStatus(adminGarageId, status);
}

export async function secureGenerateAccessCode(adminGarageId: number) {
    await verifyAdminAuth();

    // 1. Generate CRYTOGRAHICALLY SECURE 4-digit code (unlike Math.random)
    const secureCode = crypto.randomInt(1000, 10000).toString();

    const supabaseUrl = process.env.NEXT_PUBLIC_SUPABASE_URL!;
    const supabaseKey = process.env.SUPABASE_SERVICE_ROLE_KEY || process.env.NEXT_PUBLIC_SUPABASE_ANON_KEY!;
    const supabaseAdmin = createClient<Database>(supabaseUrl, supabaseKey);

    // Get admin garage
    const { data: adminGarage, error: fetchError } = await supabaseAdmin
        .from('admin_garages')
        .select('*')
        .eq('id', adminGarageId)
        .single();
    if (fetchError) throw fetchError;

    // Update Access Code
    const { error: updateError } = await (supabaseAdmin.from('admin_garages') as any)
        .update({ generated_code: secureCode })
        .eq('id', adminGarageId);
    if (updateError) throw updateError;

    // Synchronize to public garages table
    let publicGarageId = adminGarage.garage_id;

    if (publicGarageId) {
        const { error: garageUpdateError } = await (supabaseAdmin.from('garages') as any)
            .update({ access_code: secureCode })
            .eq('id', publicGarageId);
        if (garageUpdateError) throw garageUpdateError;
    } else {
        // Create new public garage
        publicGarageId = `g_${adminGarageId}_${Date.now()}`;
        const newGarage = {
            id: publicGarageId,
            name: adminGarage.name,
            address: adminGarage.address || `${adminGarage.city} Centre`,
            city: adminGarage.city,
            lat: 48.8566 + (Math.random() * 0.1), // Mock coordinates
            lng: 2.3522 + (Math.random() * 0.1),
            rating: 5.0,
            next_availability: new Date().toISOString(),
            image: 'https://images.unsplash.com/photo-1486006920555-c77dcf18193c?auto=format&fit=crop&q=80&w=800',
            access_code: secureCode,
            home_service: adminGarage.home_service || false,
            courtesy_vehicle: adminGarage.courtesy_vehicle || false,
            franchise_offerte: adminGarage.franchise_offerte || true
        };

        const { error: garageCreateError } = await (supabaseAdmin.from('garages') as any).insert(newGarage);
        if (garageCreateError) throw garageCreateError;

        // Create default offer
        const { error: offerCreateError } = await (supabaseAdmin.from('offers') as any).insert({
            id: `offer_${publicGarageId}`,
            garage_id: publicGarageId,
            price: adminGarage.offer_value || 120,
            currency: 'EUR',
            description: adminGarage.offer_description || 'Remplacement Standard',
            availability: new Date().toISOString(),
            service_duration: 120
        });
        if (offerCreateError) throw offerCreateError;

        // Link back to admin_garage
        const { error: linkError } = await (supabaseAdmin.from('admin_garages') as any)
            .update({ garage_id: publicGarageId })
            .eq('id', adminGarageId);
        if (linkError) throw linkError;
    }

    // Send the Notification Email via the Secure Module
    if (adminGarage.email) {
        await sendNotificationEmail('partner_accepted', {
            email: adminGarage.email,
            name: adminGarage.name,
            code: secureCode
        });
    }

    return secureCode;
}

