                                        >
                                            Supprimer
                                        </button>
                                    </div>
                                </div>
                            </div>
                        ))}
                        {offers.length === 0 && (
                            <div style={{ gridColumn: '1/-1', textAlign: 'center', padding: '2rem', color: '#64748b', backgroundColor: '#e2e8f0', borderRadius: '12px' }}>
                                Aucune offre active. Ajoutez-en une pour ├¬tre visible !
                            </div>
                        )}
                    </div>
                </div>

                {/* Offer Modal */}
                {isOfferModalOpen && (
                    <div style={{
                        position: 'fixed', inset: 0, backgroundColor: 'rgba(0,0,0,0.5)', zIndex: 50,
                        display: 'flex', alignItems: 'center', justifyContent: 'center'
                    }}>
                        <div style={{ backgroundColor: 'white', borderRadius: '16px', padding: '1.5rem', width: '90%', maxWidth: '500px' }}>
                            <h3 style={{ fontSize: '1.1rem', fontWeight: 700, marginBottom: '1rem' }}>
                                {editingOffer ? 'Modifier l\'offre' : 'Nouvelle offre'}
                            </h3>
                            <form onSubmit={async (e) => {
                                e.preventDefault();

                                // Calculate Final Description & Price based on Type
                                let finalDesc = '';
                                let finalPrice = 0;

                                if (offerForm.offerType === 'finance') {
                                    finalPrice = offerForm.customValue;
                                    finalDesc = `Franchise offerte jusqu'├á ${finalPrice}Γé¼`;
                                } else if (offerForm.offerType === 'gift') {
                                    finalPrice = offerForm.customValue;
                                    finalDesc = `${offerForm.customName} (${finalPrice}Γé¼)`;
                                } else {
                                    // Combined
                                    finalPrice = (offerForm.combinedRefund || 0) + (offerForm.combinedGiftValue || 0);
                                    finalDesc = `Franchise (${offerForm.combinedRefund}Γé¼) + ${offerForm.customName}`;
                                }

                                try {
                                    if (editingOffer) {
                                        const updated = await updateOffer(editingOffer.id, {
                                            description: finalDesc,
                                            price: finalPrice,
                                            currency: offerForm.currency,
                                            service_duration: offerForm.service_duration
                                        }, userGarage!.id);
                                        setOffers(prev => prev.map(o => o.id === updated.id ? updated : o));
                                    } else {
                                        const newOffer = await createOffer({
                                            garage_id: userGarage!.id,
                                            id: `offer_${Date.now()}`,
                                            description: finalDesc,
                                            price: finalPrice,
                                            currency: offerForm.currency,
                                            service_duration: offerForm.service_duration,
                                            availability: new Date().toISOString()
                                        }, userGarage!.id);
                                        setOffers(prev => [newOffer, ...prev]);
                                    }
                                    setIsOfferModalOpen(false);
                                } catch (err) {
                                    console.error(err);
                                    alert("Erreur lors de l'enregistrement");
                                }
                            }}>
                                <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>

                                    {/* OFFER TYPE SELECTOR */}
                                    <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '0.5rem' }}>
                                        <button
                                            type="button"
                                            onClick={() => setOfferForm(prev => ({ ...prev, offerType: 'finance' }))}
                                            style={{
                                                flex: 1, padding: '0.5rem', fontSize: '0.9rem', borderRadius: '6px',
                                                border: '1px solid',
                                                borderColor: offerForm.offerType === 'finance' ? '#0284C7' : '#E2E8F0',
                                                backgroundColor: offerForm.offerType === 'finance' ? '#E0F2FE' : 'white',
                                                color: offerForm.offerType === 'finance' ? '#0284C7' : '#64748B',
                                                fontWeight: 600
                                            }}
                                        >
                                            ≡ƒÆ░ Remboursement
                                        </button>
                                        <button
                                            type="button"
                                            onClick={() => setOfferForm(prev => ({ ...prev, offerType: 'gift' }))}
                                            style={{
                                                flex: 1, padding: '0.5rem', fontSize: '0.9rem', borderRadius: '6px',
                                                border: '1px solid',
                                                borderColor: offerForm.offerType === 'gift' ? '#0284C7' : '#E2E8F0',
                                                backgroundColor: offerForm.offerType === 'gift' ? '#E0F2FE' : 'white',
                                                color: offerForm.offerType === 'gift' ? '#0284C7' : '#64748B',
                                                fontWeight: 600
                                            }}
                                        >
                                            ≡ƒÄü Cadeau
                                        </button>
                                        <button
                                            type="button"
                                            onClick={() => setOfferForm(prev => ({ ...prev, offerType: 'combined' }))}
                                            style={{
                                                flex: 1, padding: '0.5rem', fontSize: '0.9rem', borderRadius: '6px',
                                                border: '1px solid',
                                                borderColor: offerForm.offerType === 'combined' ? '#0284C7' : '#E2E8F0',
                                                backgroundColor: offerForm.offerType === 'combined' ? '#E0F2FE' : 'white',
                                                color: offerForm.offerType === 'combined' ? '#0284C7' : '#64748B',
                                                fontWeight: 600
                                            }}
                                        >
                                            Γ£¿ Les deux
                                        </button>
                                    </div>

                                    {/* DYNAMIC FIELDS */}
                                    {offerForm.offerType === 'finance' ? (
                                        <div>
                                            <label style={{ display: 'block', fontSize: '0.9rem', fontWeight: 500, marginBottom: '0.25rem', color: '#0C4A6E' }}>Montant offert / Rembours├⌐</label>
                                            <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                                <input
                                                    required
                                                    type="number"
                                                    style={{ flex: 1, padding: '0.75rem', borderRadius: '6px', border: '1px solid #BAE6FD' }}
                                                    value={offerForm.customValue}
                                                    onChange={e => setOfferForm({ ...offerForm, customValue: parseInt(e.target.value) || 0 })}
                                                    placeholder="100"
                                                />
                                                <span style={{ fontWeight: 700, color: '#0369A1' }}>Γé¼</span>
                                            </div>
                                            <div style={{ fontSize: '0.8rem', color: '#64748B', marginTop: 4 }}>
                                                Sera affich├⌐ comme : &quot;Franchise offerte jusqu&apos;├á {offerForm.customValue}Γé¼&quot;
                                            </div>
                                        </div>
                                    ) : offerForm.offerType === 'gift' ? (
                                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                            <div>
                                                <label style={{ display: 'block', fontSize: '0.9rem', fontWeight: 500, marginBottom: '0.25rem', color: '#0C4A6E' }}>Nature du Cadeau</label>
                                                <input
                                                    required
                                                    type="text"
                                                    style={{ width: '100%', padding: '0.75rem', borderRadius: '6px', border: '1px solid #BAE6FD' }}
                                                    value={offerForm.customName}
                                                    onChange={e => setOfferForm({ ...offerForm, customName: e.target.value })}
                                                    placeholder="ex: Nintendo Switch Lite"
                                                />
                                            </div>
                                            <div>
                                                <label style={{ display: 'block', fontSize: '0.9rem', fontWeight: 500, marginBottom: '0.25rem', color: '#0C4A6E' }}>Valeur Estim├⌐e</label>
                                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                                    <input
                                                        required
                                                        type="number"
                                                        style={{ flex: 1, padding: '0.75rem', borderRadius: '6px', border: '1px solid #BAE6FD' }}
                                                        value={offerForm.customValue}
                                                        onChange={e => setOfferForm({ ...offerForm, customValue: parseInt(e.target.value) || 0 })}
                                                        placeholder="200"
                                                    />
                                                    <span style={{ fontWeight: 700, color: '#0369A1' }}>Γé¼</span>
                                                </div>
                                            </div>
                                        </div>
                                    ) : (
                                        <div style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                                            <div>
                                                <label style={{ display: 'block', fontSize: '0.9rem', fontWeight: 500, marginBottom: '0.25rem', color: '#0C4A6E' }}>Montant Rembours├⌐ (Franchise)</label>
                                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                                    <input
                                                        required
                                                        type="number"
                                                        style={{ flex: 1, padding: '0.75rem', borderRadius: '6px', border: '1px solid #BAE6FD' }}
                                                        value={offerForm.combinedRefund || 0}
                                                        onChange={e => setOfferForm({ ...offerForm, combinedRefund: parseInt(e.target.value) || 0 })}
                                                        placeholder="100"
                                                    />
                                                    <span style={{ fontWeight: 700, color: '#0369A1' }}>Γé¼</span>
                                                </div>
                                            </div>
                                            <div>
                                                <label style={{ display: 'block', fontSize: '0.9rem', fontWeight: 500, marginBottom: '0.25rem', color: '#0C4A6E' }}>Nature du Cadeau</label>
                                                <input
                                                    required
                                                    type="text"
                                                    style={{ width: '100%', padding: '0.75rem', borderRadius: '6px', border: '1px solid #BAE6FD' }}
                                                    value={offerForm.customName}
                                                    onChange={e => setOfferForm({ ...offerForm, customName: e.target.value })}
                                                    placeholder="ex: Carte Carburant"
                                                />
                                            </div>
                                            <div>
                                                <label style={{ display: 'block', fontSize: '0.9rem', fontWeight: 500, marginBottom: '0.25rem', color: '#0C4A6E' }}>Valeur du Cadeau</label>
                                                <div style={{ display: 'flex', alignItems: 'center', gap: '0.5rem' }}>
                                                    <input
                                                        required
                                                        type="number"
                                                        style={{ flex: 1, padding: '0.75rem', borderRadius: '6px', border: '1px solid #BAE6FD' }}
                                                        value={offerForm.combinedGiftValue || 0}
                                                        onChange={e => setOfferForm({ ...offerForm, combinedGiftValue: parseInt(e.target.value) || 0 })}
                                                        placeholder="50"
                                                    />
                                                    <span style={{ fontWeight: 700, color: '#0369A1' }}>Γé¼</span>
                                                </div>
                                            </div>
                                            <div style={{ fontSize: '0.85rem', fontWeight: 600, color: '#059669', textAlign: 'right', marginTop: '0.5rem' }}>
                                                Valeur Totale affich├⌐e : {(offerForm.combinedRefund || 0) + (offerForm.combinedGiftValue || 0)} Γé¼
                                            </div>
                                        </div>
                                    )}

                                    <div style={{ display: 'flex', justifyContent: 'end', gap: '0.75rem', marginTop: '1rem' }}>
                                        <button
                                            type="button"
                                            onClick={() => setIsOfferModalOpen(false)}
                                            style={{ padding: '0.5rem 1rem', borderRadius: '8px', border: '1px solid #cbd5e1', backgroundColor: 'white', cursor: 'pointer' }}
                                        >
                                            Annuler
                                        </button>
                                        <button
                                            type="submit"
                                            style={{ padding: '0.5rem 1rem', borderRadius: '8px', backgroundColor: '#3b82f6', color: 'white', border: 'none', fontWeight: 600, cursor: 'pointer' }}
                                        >
                                            Enregistrer
                                        </button>
                                    </div>
                                </div>
                            </form>
                        </div>
                    </div>
                )}

                {/* Appointments */}
                <div className="card" style={{ padding: '0', overflow: 'hidden' }}>
                    <div style={{ padding: '1.5rem', borderBottom: '1px solid #F1F5F9' }}>
                        <h2 style={{ fontSize: '1.25rem', margin: 0 }}>Vos Rendez-vous</h2>
                    </div>
                    <div>
                        {appointments.length === 0 ? (
                            <div style={{ padding: '2rem', textAlign: 'center', color: '#94A3B8' }}>Aucun rendez-vous pour le moment.</div>
                        ) : appointments.map(app => (
                            <div key={app.id} style={{
                                display: 'grid',
                                gridTemplateColumns: 'repeat(auto-fit, minmax(200px, 1fr))',
                                padding: '1.5rem',
                                borderBottom: '1px solid #F1F5F9',
                                alignItems: 'center',
                                gap: '1rem'
                            }}>
                                <div>
                                    {/* MASKING LOGIC */}
                                    <div style={{
                                        fontWeight: 600,
                                        color: app.status === 'En attente' ? '#64748B' : 'inherit',
                                        filter: app.status === 'En attente' ? 'blur(4px)' : 'none',
                                        userSelect: app.status === 'En attente' ? 'none' : 'auto',
                                        transition: 'filter 0.3s ease'
                                    }}>
                                        {app.client_name}
                                    </div>
                                    <div style={{ fontSize: '0.9rem', color: 'var(--color-text-secondary)', marginTop: 4 }}>
                                        {app.status === 'En attente' ? (
                                            <div style={{ color: '#94A3B8', fontStyle: 'italic' }}>
                                                Infos masqu├⌐es avant confirmation
                                            </div>
                                        ) : (
                                            <>
                                                <div>Ref: VTR-{app.id}</div>
                                                <div>{app.phone}</div>
                                                <div>{app.email}</div>
                                            </>
                                        )}
                                    </div>
                                    <div style={{ fontSize: '0.85rem', color: 'var(--color-text-muted)', marginTop: 4 }}>
                                        {app.vehicle} ΓÇó <span style={{ fontWeight: 500 }}>{app.offers[0]}</span>
                                    </div>
                                </div>

                                <div style={{ color: 'var(--color-text-main)' }}>
                                    {format(new Date(app.date), "dd MMM yyyy ├á HH:mm", { locale: fr })}
                                </div>

                                <div>
                                    <span style={{
                                        padding: '0.25rem 0.75rem',
                                        borderRadius: '999px',
                                        fontSize: '0.85rem',
                                        fontWeight: 600,
                                        backgroundColor: app.status === 'En attente' ? '#FEF9C3' : app.status === 'Confirm├⌐' ? '#E0F2FE' : '#DCFCE7',
                                        color: app.status === 'En attente' ? '#854D0E' : app.status === 'Confirm├⌐' ? '#0369A1' : '#166534',
                                        display: 'inline-block'
                                    }}>
                                        {app.status}
                                    </span>
                                    {app.billing_triggered && (
                                        <span style={{ marginLeft: '0.5rem', fontSize: '0.8rem', color: '#059669', fontWeight: 700 }}>
                                            Γ£ô Factur├⌐
                                        </span>
                                    )}
                                </div>

                                <div style={{ textAlign: 'right' }}>
                                    {app.status === 'En attente' && (
                                        <div style={{ display: 'flex', flexDirection: 'column', alignItems: 'flex-end', gap: '0.5rem' }}>
                                            <button
                                                onClick={() => handleToggleStatus(app.id, app.status)}
                                                className="btn"
                                                style={{
                                                    padding: '0.5rem 1rem',
                                                    fontSize: '0.9rem',
                                                    backgroundColor: 'var(--color-primary)',
                                                    color: 'white'
                                                }}
                                            >
                                                Accepter & Voir ({app.amount}Γé¼)
                                            </button>
                                            <span style={{ fontSize: '0.75rem', color: '#64748B' }}>D├⌐clenche la facturation</span>
                                        </div>
                                    )}
                                    {app.status === 'Confirm├⌐' && (
                                        <button
                                            onClick={() => handleToggleStatus(app.id, app.status)}
                                            className="btn"
                                            style={{
                                                padding: '0.5rem 1rem',
                                                fontSize: '0.9rem',
                                                backgroundColor: 'var(--color-secondary)',
                                                color: 'white'
                                            }}
                                        >
                                            Marquer Termin├⌐
                                        </button>
                                    )}
                                    {app.status === 'Termin├⌐' && (
                                        <div style={{ fontWeight: 700, color: 'var(--color-text-main)', fontSize: '1.2rem' }}>
                                            Termin├⌐
                                        </div>
                                    )}
                                </div>
                            </div>
                        ))}
                    </div>
                </div>
            </main>
        </div>
    );
}

"use client";

import { useState } from "react";
import Link from "next/link";
import { useRouter } from "next/navigation";
import { submitPartnerRegistration } from "@/app/actions";

export default function RegisterPro() {
    const router = useRouter();
    const [loading, setLoading] = useState(false);

    const [formData, setFormData] = useState({
        name: "",
        siret: "",
        city: "",
        address: "",
        email: "",
        phone: "",
        offerType: 'finance' as 'finance' | 'gift' | 'combined',
        customName: "",
        customValue: 0,
        combinedRefund: 0,
        combinedGiftValue: 0,
        homeService: false,
        courtesyVehicle: false
    });

    const handleSubmit = async (e: React.FormEvent) => {
        e.preventDefault();
        setLoading(true);

        try {
            // Logic to construct offer
            let description = "";
            let effectivePrice = 0;

            if (formData.offerType === 'finance') {
                description = `Franchise offerte (jusqu'├á ${formData.customValue}Γé¼)`;
                effectivePrice = formData.customValue;
            } else if (formData.offerType === 'combined') {
                // Combined: Refund + Gift
                const refund = formData.combinedRefund || 0;
                const giftVal = formData.combinedGiftValue || 0;
                const giftName = formData.customName || 'Cadeau';
                description = `Franchise (${refund}Γé¼) + ${giftName}`;
                effectivePrice = refund + giftVal;
            } else {
                description = `${formData.customName} Offert(e) (Val. ${formData.customValue}Γé¼)`;
                effectivePrice = formData.customValue;
            }

            // Create admin garage securely via Server Action
            await submitPartnerRegistration({
                name: formData.name,
                city: formData.city,
                address: formData.address,
                email: formData.email,
                phone: formData.phone,
                siret: formData.siret,
                status: 'En attente',
                registration_date: new Date().toISOString().split('T')[0],
                garage_id: null,
                generated_code: null,
                offer_value: effectivePrice,
                offer_description: description,
                home_service: formData.homeService,
                courtesy_vehicle: formData.courtesyVehicle,
                franchise_offerte: formData.offerType === 'finance' || formData.offerType === 'combined'
            });

            alert('Inscription envoy├⌐e ! Vous recevrez un email avec votre code d\'acc├¿s une fois valid├⌐ par l\'admin.');
            router.push('/pro');
        } catch (error: any) {
            console.error('Full registration error object:', error);
            alert(`Erreur lors de l'inscription: ${error?.message || 'Veuillez r├⌐essayer.'}`);
        } finally {
            setLoading(false);
        }
    };

    return (
        <div style={{ minHeight: '100vh', backgroundColor: '#F8FAFC', display: 'flex', flexDirection: 'column' }}>
            {/* Header */}
            <nav className="container" style={{ padding: '1rem 0', display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                <Link href="/" style={{ fontSize: '1.25rem', fontWeight: 800, color: 'var(--color-primary)' }}>Vitrio <span style={{ color: 'var(--color-text-main)', fontWeight: 400 }}>Pro</span></Link>
                <Link href="/pro" style={{ fontSize: '0.9rem', color: 'var(--color-text-secondary)' }}>&larr; Retour</Link>
            </nav>

            <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center', padding: '2rem 1rem' }}>
                <div className="card" style={{ maxWidth: '500px', width: '100%', padding: '2.5rem' }}>
                    <h1 style={{ fontSize: '1.5rem', fontWeight: 700, marginBottom: '0.5rem', textAlign: 'center' }}>
                        Rejoignez le r├⌐seau Vitrio
                    </h1>
                    <p style={{ textAlign: 'center', color: 'var(--color-text-secondary)', marginBottom: '2rem' }}>
                        Inscription gratuite et sans engagement.
                    </p>

                    <form onSubmit={handleSubmit} style={{ display: 'flex', flexDirection: 'column', gap: '1rem' }}>
                        <div>
                            <label style={{ display: 'block', fontSize: '0.9rem', fontWeight: 500, marginBottom: '0.25rem' }}>Nom du Garage</label>
                            <input
                                required
                                type="text"
                                className="input-field"
                                style={{ width: '100%', padding: '0.75rem', borderRadius: '6px', border: '1px solid #E2E8F0' }}
                                value={formData.name}
                                onChange={e => setFormData({ ...formData, name: e.target.value })}
                                placeholder="ex: AutoGlass Paris"
                            />
                        </div>

                        <div>
                            <label style={{ display: 'block', fontSize: '0.9rem', fontWeight: 500, marginBottom: '0.25rem' }}>Num├⌐ro SIRET</label>
                            <input
                                required
                                type="text"
                                style={{ width: '100%', padding: '0.75rem', borderRadius: '6px', border: '1px solid #E2E8F0' }}
                                value={formData.siret}
                                onChange={e => setFormData({ ...formData, siret: e.target.value })}
                                placeholder="123 456 789 00012"
                            />
                        </div>

                        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: '1rem' }}>
                            <div style={{ gridColumn: 'span 2' }}>
                                <label style={{ display: 'block', fontSize: '0.9rem', fontWeight: 500, marginBottom: '0.25rem' }}>Adresse compl├¿te</label>
                                <input
                                    required
                                    type="text"
                                    style={{ width: '100%', padding: '0.75rem', borderRadius: '6px', border: '1px solid #E2E8F0' }}
                                    value={formData.address}
                                    onChange={e => setFormData({ ...formData, address: e.target.value })}
                                    placeholder="ex: 123 rue de Rivoli, 75001 Paris"
                                />
                            </div>
                            <div>
                                <label style={{ display: 'block', fontSize: '0.9rem', fontWeight: 500, marginBottom: '0.25rem' }}>Ville</label>
                                <input
                                    required
                                    type="text"
                                    style={{ width: '100%', padding: '0.75rem', borderRadius: '6px', border: '1px solid #E2E8F0' }}
                                    value={formData.city}
                                    onChange={e => setFormData({ ...formData, city: e.target.value })}
                                    placeholder="Paris"
                                />
                            </div>
                            <div>
                                <label style={{ display: 'block', fontSize: '0.9rem', fontWeight: 500, marginBottom: '0.25rem' }}>T├⌐l├⌐phone</label>
                                <input
                                    required
                                    type="tel"
                                    style={{ width: '100%', padding: '0.75rem', borderRadius: '6px', border: '1px solid #E2E8F0' }}
                                    value={formData.phone}
                                    onChange={e => setFormData({ ...formData, phone: e.target.value })}
                                    placeholder="01 23 45 67 89"
                                />
                            </div>
                        </div>

                        <div>
                            <label style={{ display: 'block', fontSize: '0.9rem', fontWeight: 500, marginBottom: '0.25rem' }}>Email Professionnel</label>
                            <input
                                required
                                type="email"
                                style={{ width: '100%', padding: '0.75rem', borderRadius: '6px', border: '1px solid #E2E8F0' }}
                                value={formData.email}
                                onChange={e => setFormData({ ...formData, email: e.target.value })}
                                placeholder="contact@garage.com"
                            />
                        </div>

                        {/* OFFER SECTION */}
                        <div style={{ marginTop: '1rem', padding: '1rem', backgroundColor: '#F0F9FF', borderRadius: '8px', border: '1px solid #BAE6FD' }}>
                            <h3 style={{ fontSize: '1rem', fontWeight: 700, marginBottom: '1rem', color: '#0369A1' }}>Votre Offre Vitrio</h3>

                            {/* Toggle Type */}
                            <div style={{ display: 'flex', gap: '0.5rem', marginBottom: '1rem' }}>
                                <button
                                    type="button"
                                    onClick={() => setFormData(prev => ({ ...prev, offerType: 'finance' }))}
                                    style={{
                                        flex: 1,
                                        padding: '0.5rem',
                                        fontSize: '0.9rem',
                                        borderRadius: '6px',
                                        border: '1px solid',
                                        borderColor: formData.offerType === 'finance' ? '#0284C7' : '#E2E8F0',
                                        backgroundColor: formData.offerType === 'finance' ? '#E0F2FE' : 'white',
                                        color: formData.offerType === 'finance' ? '#0284C7' : '#64748B',
                                        fontWeight: 600
                                    }}
                                >
                                    ≡ƒÆ░ Remboursement
